class Solution(object):
    def sortString(self, s):
        from collections import Counter
        freq = Counter(s)
        result = []
        while freq:
            for char in sorted(freq.keys()):
                result.append(char)
                freq[char] -= 1
                if freq[char] == 0:
                    del freq[char]
            for char in sorted(freq.keys(), reverse=True):
                result.append(char)
                freq[char] -= 1
                if freq[char] == 0:
                    del freq[char]
        return ''.join(result)
